import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"异想体书页—总类层","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/异想体书页/异想体书页—总类层.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/异想体书页/异想体书页—总类层.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/异想体书页/异想体书页—总类层.md"};function d(o,p,_,l,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"异想体书页—总类层",tabindex:"-1"},[t("异想体书页—总类层 "),r("a",{class:"header-anchor",href:"#异想体书页—总类层","aria-label":'Permalink to "异想体书页—总类层"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="异想体书页——总类层" tabindex="-1">异想体书页——总类层 <a class="header-anchor" href="#异想体书页——总类层" aria-label="Permalink to &quot;异想体书页——总类层&quot;">​</a></h1><p>异想体书页——总类层</p><p>该功能是图书馆馆长借助图书馆使司书与书中记录的异想体共鸣，初始不开启，直到轮回者通过第一个异想体的试炼为止<br> 通过记录在书中的异想体的试炼之后开放对应异想体书页的购买<br> 每提升一次情感等级，都可以选择一次异想体书页，不同异想体书页要求的负面/正面情感硬币数量不同<br> 以下的书页分为崩溃书页/觉醒书页，书页的选取有情感等级限制，只有到达对应情感等级才能选取<br> 异想体书页在选择后立即生效，效果持续一场景。同一书页不可重复选取。</p><p>血浴缸对应书页</p><p>疤痕<br> D+500<br> 觉醒书页<br> 要求：正面情感硬币数量＞负面情感硬币数量</p><p>——当我注视着她那伤痕累累的手腕时，我想起了我们的酒窖。<br> 那一夜，我把最后一瓶喝的精光。</p><p>司书在应用该书页后，获得1DR/-<br> 在司书被对方以攻击击中时，进行一次d10的自然骰，如结果大于4<br> 则在应对此次攻击中，司书视作拥有【全伤害吸收2】</p><p>惨白之手<br> D+500<br> 觉醒书页<br> 要求：正面情感硬币数量＞负面情感硬币</p><p>——我触碰到了冰冷而僵硬的手。<br> 我曾深爱之人的手。</p><p>应用该书页后，当司书对上轮自己攻击的目标再次发动攻击命中后，会附带一点不可豁免的精神束缚点数，<br> 如果下一轮攻击目标依旧不变，则附带的精神束缚点数再+1，最多叠加至附带三点不可豁免的精神束缚点数</p><p>鲜血<br> C+1000<br> 崩溃书页<br> 要求：负面情感硬币数量＞正面情感硬币数量</p><p>——望向浴缸内部，你会莫名感到无法承受的忧郁</p><p>应用该书页后，司书在面对攻击时获得【全伤害吸收3】<br> 获得4点天生防御以及基于天生防御的【防弹】【防能量】<br> 司书现在不在受到来自冲击点数的减值<br> 但是司书现在每次受到攻击，如果这次攻击没有被防御及防御上的附加成功减去全部成功数，那么司书将额外受到一点不可豁免的冲击点数</p><p>渴望之心对应书页</p><p>脉动<br> D+500<br> 崩溃书页<br> 要求：负面情感硬币数量＞正面情感硬币数量</p><p>——过度的渴望会使人发狂</p><p>应用该书页后，司书的攻击检定获得+4DP以及1点附加成功，这是增强加值<br> 并且攻击额外获得【高速5】<br> 每一轮结束时，如果本轮司书没有成功造成伤害，那么司书将会受到不可避免的2点严重伤害。</p><p>渴望<br> D+500<br> 觉醒书页<br> 要求：无</p><p>——携带者的心率瞬间提升到2倍以上，<br> 并获得惊人的肌肉活力与力量</p><p>应用该书页后，本场景内先攻+6，这会改变行动顺序。<br> 立即获得2点临时生命。<br> 并且在攻击先攻低于司书的敌人时，司书的攻击获得+3DP，这是增强加值。</p><p>剧烈搏动<br> C+1000<br> 崩溃书页<br> 要求：负面情感硬币数量至少有三枚</p><p>——一颗无主之心，即使与身体分离也从未停止跳动</p><p>应用该书页的司书，本场景内先攻+6<br> 现在司书即使生命槽中最好的状态为严重也不会进入眩晕，免疫A级及以下的混乱效果且不会因为混乱抗性归零而进入混乱状态。<br> 司书的攻击检定获得+8DP以及+4附加成功，这是增强加值。<br> 在应用该书页后，该司书第三次结束回合时，若仍然没有结束战斗，则会不可避免的受到耐力属性点严重伤害。</p><p>匹诺曹对应书页</p><p>谎言<br> D+500<br> 崩溃书页<br> 要求：负面情感硬币数量＞正面情感硬币数量</p><p>——人人都在说谎，这有啥不好的？</p><p>应用该书页的司书，每次使用能量消耗在3及以下的书页时，投掷D4-1，将结果替代这一书页原先的能量消耗。<br> 每轮一次，该司书的所有敌人在使用能量攻击该司书时，需要进行一次d7-1，敌人这次攻击的能量消耗增加出目点。<br> ST有权简化该过程，仅在应用该书页的时候进行一次检定，作为双方的能量消耗调整值<br> 应用该书页后的司书，在攻击时可以选择不造成伤害，而是将造成的伤害转为减少对方等量点能量。</p><p>好奇<br> D+500<br> 崩溃书页<br> 要求：负面情感硬币数量＞正面情感硬币数量</p><p>——我今天也在努力学习，要向你展示一下吗？</p><p>应用该书页的司书每轮开始时获得2AP，仅限于使用战斗书页。<br> 当该司书在自己回合外使用动作时，若该动作会消耗光芒，则回复一点光芒。<br> 仅在本回合，该司书获得额外的2AP，仅限于使用战斗书页。</p><p>学习<br> C+1000<br> 觉醒书页<br> 要求：无</p><p>——这家伙只会跟在别人身后“学习”，而这就是问题所在</p><p>应用该书页的司书，在这轮结束时，获得本轮敌人造成伤害类型的对应抗性，即【远程伤害吸收4】或【近战伤害吸收4】，仅生效一次。<br> 在下一轮结束时，获得敌人抗性最高的防御对应的破防8点，仅生效一次<br> 在第三轮结束时，获得攻击检定上的+5DP和+1附加成功，这是增强加值，仅生效一次</p><p>冰雪女皇对应书页</p><p>凌剑<br> C+1000<br> 觉醒书页<br> 要求：正面情感硬币数量＞负面情感硬币数量</p><p>——寒冷的冬林中，唯有一位女皇</p><p>应用该书页的司书的攻击可以转化为造成等值的冻结点数，标准豁免。此时攻击范围变为15米范围的圆形。<br> 此时的攻击视为具有【法破】<br> 该司书的攻击获得【毁灭】</p><p>亲吻<br> B+2000<br> 觉醒书页<br> 要求：正面情感硬币数量＞负面情感硬币数量</p><p>——冰雪女皇的吻冰封了他的内心，使他不在寒冷</p><p>应用该书页的司书在拼点胜利后，会对敌人施加一层“霜凌”<br> 每一轮结束时，“霜凌”层数大于2的敌人将在一轮内陷入震慑状态，无法行动，这个是A级环境来源的效果随后重置层数。<br> 应用该书页的司书进行攻击时会附带等值冻结点数，正常豁免<br> 应用该书页的司书的攻击视作接触攻击</p><p>雪暴<br> B+2000<br> 崩溃书页<br> 要求：负面情感硬币数量＞正面情感硬币数量</p><p>——玫瑰盛开，雪宫崩塌。<br> 欢笑的人们不曾记得，在那有位沉睡的美人。</p><p>应用该书页的下一轮开始，对司书周围120米半径的圆形范围的所有人进行一次攻击检定，强韧豁免，失败者陷入定身状态，这是A级环境来源的效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',45)])])}const f=b(s,[["render",d]]);export{D as __pageData,f as default};
